import React, { useEffect, useRef } from 'react';
import { Form, FormField } from '../ppm/cms/form-builder/FormBuilderTypes';

type FormRendererProps = {
  form: Form;
  disabled?: boolean;
};

const FormRenderer: React.FC<FormRendererProps> = ({ form, disabled = false }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  // Generate a unique key if field.id is missing
  const getFieldKey = (field: FormField, index: number) => field.id || `field_${index}`;

  // ✅ VALIDATOR
  const validateField = (field: FormField, value: any) => {
    let isValid = true;

    // Normalize value
    const normalizedValue = typeof value === 'string' ? value.trim() : value;

    // Required check
    if (field.required) {
      if (
        normalizedValue === undefined ||
        normalizedValue === null ||
        normalizedValue === '' ||
        (Array.isArray(normalizedValue) && normalizedValue.length === 0)
      ) {
        isValid = false;
      }
    }

    // Email validation
    // if (field.type === 'email_address' && normalizedValue) {
    //   const emailRegex = /^[^\s@]+@[^\s@]+(\.[a-zA-Z]{2,63})+$/;
    //   isValid = emailRegex.test(normalizedValue);
    // }

    console.log(
      `[VALIDATION] Field: ${field.name} | Value: ${normalizedValue} | ${isValid ? 'PASS' : 'FAIL'}`
    );

    return isValid;
  };

  // ✅ VALIDATE WHOLE FORM
  const runValidation = () => {
    if (!containerRef.current) return;

    const values: Record<string, any> = {};
    const formEl = containerRef.current.closest('form');
    if (!formEl) return;

    const formData = new FormData(formEl);
    formData.forEach((value, key) => {
      if (values[key]) {
        if (Array.isArray(values[key])) {
          values[key].push(value);
        } else {
          values[key] = [values[key], value];
        }
      } else {
        values[key] = value;
      }
    });

    console.log("Collected values:", values);

    let allValid = true;

    form.fields.forEach((field, index) => {
      const key = getFieldKey(field, index);
      const value = values[key];

      if (value === undefined) {
        console.warn(`❌ Field "${field.name}" completely missing. field.id="${key}"`);
      }

      const valid = validateField(field, value);
      if (!valid) allValid = false;
    });

    if (allValid) {
      console.log("FORM VALID: PASS ✅");
    } else {
      console.log("FORM VALID: FAIL ❌ — form submission would be blocked");
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const handler = () => runValidation();

    el.addEventListener('input', handler);
    el.addEventListener('change', handler);

    return () => {
      el.removeEventListener('input', handler);
      el.removeEventListener('change', handler);
    };
  }, [form]);

  const renderField = (field: FormField, index: number) => {
    const key = getFieldKey(field, index);

    const commonProps = {
      id: key,
      name: key,
      required: field.required,
      disabled: disabled
    };

    switch (field.type) {
case 'short_answer':
  return (
    <div key={key} className="form-group">
      <label htmlFor={key}>
        {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
      </label>
      <input
        type="text"
        {...commonProps}
        placeholder={field.placeholder || ''}
      />
    </div>
  );

  case 'email_address':
  return (
    <div key={key} className="form-group">
      <label htmlFor={key}>
        {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
      </label>
      <input
        type="email"
        {...commonProps}
        placeholder={field.placeholder || ''}
        pattern="^[^\s@]+@[^\s@]+(\.[a-zA-Z]{2,63})+$" // <-- stricter TLD check
        title="Email không hợp lệ. Ví dụ: user@example.com" // <-- popup message
      />
    </div>
  );
case 'date':
  return (
    <div key={key} className="form-group">
      <label htmlFor={key}>
        {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
      </label>
      <input
        type="text"
        {...commonProps}
        placeholder={field.placeholder || 'dd/mm/yyyy'}
        maxLength={10} // 2+1+2+1+4 = 10 chars including slashes
        title="Ngày không hợp lệ. Vui lòng nhập định dạng dd/mm/yyyy"
        onInput={e => {
          const input = e.currentTarget as HTMLInputElement;
          // Keep only digits
          let digits = input.value.replace(/\D/g, '');

          // Auto-insert slashes
          if (digits.length > 2 && digits.length <= 4) {
            digits = digits.slice(0, 2) + '/' + digits.slice(2);
          } else if (digits.length > 4) {
            digits = digits.slice(0, 2) + '/' + digits.slice(2, 4) + '/' + digits.slice(4, 8);
          }

          input.value = digits;
        }}
        onBlur={e => {
          const input = e.currentTarget as HTMLInputElement;
          const pattern = /^\d{2}\/\d{2}\/\d{4}$/;
          if (!pattern.test(input.value)) {
            input.setCustomValidity('Ngày không hợp lệ. Vui lòng nhập định dạng dd/mm/yyyy');
          } else {
            input.setCustomValidity(''); // clear error
          }
        }}
      />
    </div>
  );

case 'phone_number':
  return (
    <div key={key} className="form-group">
      <label htmlFor={key}>
        {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
      </label>
      <input
        type="tel"
        {...commonProps}
        placeholder={field.placeholder || 'VD: 0912345678 hoặc +84123456789'}
        // title shows popup if HTML5 validation fails
        title="Số điện thoại không hợp lệ. Nhập ít nhất 10 chữ số và tối đa 15 chữ số, chỉ dùng số và dấu + ở đầu."
        onInput={e => {
          const input = e.currentTarget as HTMLInputElement;
          // Keep only digits and optional leading +
          input.value = input.value.replace(/[^\d+]/g, '');
          // Optional: allow only one leading +
          if (input.value.indexOf('+') > 0) {
            input.value = input.value.replace(/\+/g, '');
          }
        }}
        onBlur={e => {
          const input = e.currentTarget as HTMLInputElement;
          const digitsOnly = input.value.replace(/\D/g, '');
          if (digitsOnly.length < 10 || digitsOnly.length > 15) {
            input.setCustomValidity('Số điện thoại phải có từ 10 đến 15 chữ số.');
          } else {
            input.setCustomValidity(''); // clear error
          }
        }}
      />
    </div>
  );
      case 'paragraph':
        return (
          <div key={key} className="form-group" style={{ gridColumn: 'span 2' }}>
            <label htmlFor={key}>
              {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
            </label>
            <textarea {...commonProps} rows={4} placeholder={field.placeholder || ''} />
          </div>
        );

case 'multiple_choice':
  return (
    <div key={key} className="form-group">
      <label>
        {field.name} {field.required && <span style={{ color: '#e74c3c' }}>*</span>}
      </label>
      <div className="radio-group">
        {field.options.map((option, idx) => (
          <label key={idx}>
            <input
              type="radio"
              name={key}
              value={option}
              disabled={disabled}
              required={field.required && idx === 0} // 👈 THIS is the trick
            />
            {option}
          </label>
        ))}
      </div>
    </div>
  );

      case 'dropdown':
        return (
          <div key={key} className="form-group">
            <label htmlFor={key}>{field.name}</label>
            <select {...commonProps}>
              <option value="">{field.placeholder || '-- Chọn --'}</option>
              {field.options.map((option, idx) => (
                <option key={idx} value={option}>
                  {option}
                </option>
              ))}
            </select>
          </div>
        );

      case 'checkboxes':
        return (
          <div key={key} className="form-group" style={{ gridColumn: 'span 2' }}>
            <label>{field.name}</label>
            <div className="radio-group">
              {field.options.map((option, idx) => (
                <label key={idx}>
                  <input type="checkbox" name={key} value={option} disabled={disabled} />
                  {option}
                </label>
              ))}
            </div>
          </div>
        );
      case 'time':
        return (
          <div key={key} className="form-group">
            <label htmlFor={key}>{field.name}</label>
            <input type="time" {...commonProps} />
          </div>
        );

      case 'file_upload':
        return (
          <div key={key} className="form-group">
            <label htmlFor={key}>{field.name}</label>
            <input type="file" {...commonProps} />
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div
      ref={containerRef}
      className={`form-grid-renderer ${disabled ? 'disabled' : ''}`}
    >
      {form.fields.map((field, index) => renderField(field, index))}
    </div>
  );
};

export default FormRenderer;