export const MAX_CHUNK_SIZE = 190
// ===== PEM HELPERS =====

const pemToArrayBuffer = (pem: string): ArrayBuffer => {
  const base64 = pem
    .replace(/-----BEGIN [^-]+-----/, "")
    .replace(/-----END [^-]+-----/, "")
    .replace(/\s/g, "");

  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);

  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }

  return bytes.buffer;
};

const importPublicKey = async (publicKeyPem: string): Promise<CryptoKey> => {
  return await window.crypto.subtle.importKey(
    "spki",
    pemToArrayBuffer(publicKeyPem),
    { name: "RSA-OAEP", hash: "SHA-256" },
    true,
    ["encrypt"]
  );
};

const importPrivateKey = async (privateKeyPem: string): Promise<CryptoKey> => {
  return await window.crypto.subtle.importKey(
    "pkcs8",
    pemToArrayBuffer(privateKeyPem),
    { name: "RSA-OAEP", hash: "SHA-256" },
    true,
    ["decrypt"]
  );
};

// ===== BASE64 HELPERS =====

const arrayBufferToBase64 = (buffer: ArrayBuffer): string => {
  return btoa(String.fromCharCode(...new Uint8Array(buffer)));
};

const base64ToUint8Array = (base64: string): Uint8Array => {
  const binary = atob(base64);
  return new Uint8Array([...binary].map((c) => c.charCodeAt(0)));
};

// ===== MAIN FUNCTIONS =====

// Encrypt LARGE string
export const encrypt = async (
  value: string,
  publicKeyPem: string,
  chunkSize = 190
): Promise<string> => {
  const publicKey = await importPublicKey(publicKeyPem);

  const encoder = new TextEncoder();
  const data = encoder.encode(value);

  const safeChunkSize = Math.max(1, Math.min(chunkSize, 190));
  const chunks: string[] = [];

  for (let i = 0; i < data.length; i += safeChunkSize) {
    const chunk = data.slice(i, i + safeChunkSize);

    const encryptedBuffer = await window.crypto.subtle.encrypt(
      { name: "RSA-OAEP" },
      publicKey,
      chunk
    );

    chunks.push(arrayBufferToBase64(encryptedBuffer));
  }

  return JSON.stringify({ chunks });
};

// Decrypt LARGE string
export const decrypt = async (
  encryptedValue: string,
  privateKeyPem: string
): Promise<string> => {
  const privateKey = await importPrivateKey(privateKeyPem);

  let parsed: { chunks: string[] };

  try {
    parsed = JSON.parse(encryptedValue);
  } catch {
    throw new Error("Invalid encrypted payload");
  }

  const decryptedParts: Uint8Array[] = [];

  for (const chunkBase64 of parsed.chunks) {
    const chunkBytes = base64ToUint8Array(chunkBase64);

    const decryptedBuffer = await window.crypto.subtle.decrypt(
      { name: "RSA-OAEP" },
      privateKey,
      chunkBytes
    );

    decryptedParts.push(new Uint8Array(decryptedBuffer));
  }

  const totalLength = decryptedParts.reduce((sum, p) => sum + p.length, 0);
  const merged = new Uint8Array(totalLength);

  let offset = 0;
  for (const part of decryptedParts) {
    merged.set(part, offset);
    offset += part.length;
  }

  const decoder = new TextDecoder();
  return decoder.decode(merged);
};