import { useState, useEffect } from 'react';
import { Form } from '../components/ppm/cms/form-builder/FormBuilderTypes';
import { useResolved } from '../ppm/util/ResolvedContentContext';
import { useFormDataLocalstorage } from './useFormDataLocalhost';
import { useRemoteForm } from '../components/ppm/forms/useRemoteFormDefinition';


// test will be applied to localstorage

type FormKeyType = {
    default: string;
    local: string;
};

export const useResolvedFormData = ( formKey : FormKeyType, pageResoltionData ?: any, test ?: { version ?: number, clear ?: boolean  }) => {
    
    let localstorageTest : any = {
        ...test, 
        // clear : true, // clear localstorage by key
        // version : 3, // set version for testing to make sure override works
    }
    
    console.log(formKey)

    const [form, setForm] = useState<Form | null>(null);
    const [loading, setLoading] = useState(true);
    const [logs, setLogs] = useState<string[]>([]);
    const [nonLocalStorageVersion, setNonLocalStorageVersion] = useState<number>(0);

    const formLocalRaw = pageResoltionData ?? useResolved().pages.page3[formKey.local]
    const { formData : formRemoteRaw } = useRemoteForm(formKey.default);
    const { form : formLocalstorageRaw } = useFormDataLocalstorage(formKey.default, localstorageTest);

    const formLocal : any = formLocalRaw?.form
    const formRemote : any = formRemoteRaw?.form
    const formLocalstorage : any = formLocalstorageRaw

    // ─────────────────────────────────────────────
    // LOAD: remote + local merge
    // ─────────────────────────────────────────────
    useEffect(() => {
        let mounted = true;

        const getVersion = (f: any) =>
            typeof f?.version === 'number' ? f.version : 0;

        const load = async () => {
            setLoading(true);

            let chosen: Form | null = null;
            let logMessages: string[] = [];

            // 🔍 existence logs
            if (!formLocal) logMessages.push(`missing: local`);
            if (!formRemote) logMessages.push(`missing: remote`);
            if (!formLocalstorage) logMessages.push(`missing: localstorage`);

            const vLocal = getVersion(formLocal);
            const vRemote = getVersion(formRemote);
            const vLocalstorage = getVersion(formLocalstorage);

            console.group()
            console.log(formLocal)
            console.log(formRemote)
            console.log(formLocalstorage)
            console.groupEnd()

            // 🔥 compute non-localstorage version
            const nonLocalMax = Math.max(vLocal, vRemote);
            setNonLocalStorageVersion(nonLocalMax);

            logMessages.push(`versions → local:${vLocal} remote:${vRemote} localstorage:${vLocalstorage}`);

            const maxVersion = Math.max(vLocal, vRemote, vLocalstorage);

            // (1) highest version wins (only time local-storage wins is when it has highest version otherwise it will never be used)
            if (vLocalstorage === maxVersion && formLocalstorage) {
                chosen = formLocalstorage;
                logMessages.push(`winner: localstorage (version ${vLocalstorage})`);
            } else if (vLocal === maxVersion && formLocal) {
                chosen = formLocal;
                logMessages.push(`winner: local (version ${vLocal})`);
            } else if (vRemote === maxVersion && formRemote) {
                chosen = formRemote;
                logMessages.push(`winner: remote (version ${vRemote})`);
            }

            // (2) else local > remote
            if (!chosen) {
                if (formLocal) {
                    chosen = formLocal;
                    logMessages.push(`fallback winner: local`);
                } else if (formRemote) {
                    chosen = formRemote;
                    logMessages.push(`fallback winner: remote`);
                } else {
                    logMessages.push(`no data available`);
                }
            }

            if (!mounted) return;

            setForm(chosen ?? null);
            setLogs(logMessages);
            setLoading(false);
        };

        load();

        return () => {
            mounted = false;
        };
    }, [formLocal, formRemote, formLocalstorage]);

    return {
        form,
        loading,
        logs,
        nonLocalStorageVersion
    };
};