import { useCallback } from "react";

type FormFields = Record<string, string>;

type UseGoogleFormSubmitParams = {
  formId: string;
};

export const useGoogleFormSubmit = ({ formId }: UseGoogleFormSubmitParams) => {
  const submit = useCallback(async (fields: FormFields) => {
    const url = `https://docs.google.com/forms/d/e/${formId}/formResponse`;

    const body = new URLSearchParams();

    Object.entries(fields).forEach(([entryId, value]) => {
      body.append(entryId, value);
    });

    try {
      await fetch(url, {
        method: "POST",
        mode: "no-cors",
        headers: {
          "Content-Type": "application/x-www-form-urlencoded",
        },
        body,
      });

      return { success: true };
    } catch (err) {
      return { success: false, error: err };
    }
  }, [formId]);

  return { submit };
};